class Solution:
    def minDistinctAfterSwap(self, resA: str, resB: str) -> int:
        countA = [0] * 26
        countB = [0] * 26
        for c in resA:
            countA[ord(c) - ord("a")] += 1
        for c in resB:
            countB[ord(c) - ord("a")] += 1

        # 当前两串的不同字符个数
        dA = sum(1 for x in countA if x > 0)
        dB = sum(1 for x in countB if x > 0)

        ans = -1
        for a in range(26):
            if countA[a] == 0:
                continue
            for b in range(26):
                if countB[b] == 0:
                    continue
                if a == b:
                    # 交换相同字符，字符串不变；仅当原本已相等才合法
                    if dA != dB:
                        continue
                    cand = dA
                else:
                    # 按频次公式 O(1) 计算交换后的不同字符数
                    da = dA - (1 if countA[a] == 1 else 0) + (1 if countA[b] == 0 else 0)
                    db = dB - (1 if countB[b] == 1 else 0) + (1 if countB[a] == 0 else 0)
                    if da != db:
                        continue
                    cand = da
                # 多种合法交换时取不同字符数的最小值
                if ans == -1 or cand < ans:
                    ans = cand
        return ans
```

```java
public class Solution {
    public int minDistinctAfterSwap(String resA, String resB) {
        int[] countA = new int[26];
        int[] countB = new int[26];
        for (int i = 0; i < resA.length(); i++) {
            countA[resA.charAt(i) - 'a']++;
        }
        for (int i = 0; i < resB.length(); i++) {
            countB[resB.charAt(i) - 'a']++;
        }

        int dA = 0, dB = 0;
        for (int i = 0; i < 26; i++) {
            if (countA[i] > 0) dA++;
            if (countB[i] > 0) dB++;
        }

        int ans = -1;
        for (int a = 0; a < 26; a++) {
            if (countA[a] == 0) continue;
            for (int b = 0; b < 26; b++) {
                if (countB[b] == 0) continue;
                int cand;
                if (a == b) {
                    // 同字符交换不改变两串，必须原本不同字符数已相等
                    if (dA != dB) continue;
                    cand = dA;
                } else {
                    // 交换 ca=a 与 cb=b 后，用频次判断 distinct 的增减
                    int da = dA - (countA[a] == 1 ? 1 : 0) + (countA[b] == 0 ? 1 : 0);
                    int db = dB - (countB[b] == 1 ? 1 : 0) + (countB[a] == 0 ? 1 : 0);
                    if (da != db) continue;
                    cand = da;
                }
                if (ans == -1 || cand < ans) ans = cand;
            }
        }
        return ans;
    }
}
